  constructor(http, dialog, paginatorIntl) {
    this.http = http;
    this.dialog = dialog;
    this.paginatorIntl = paginatorIntl;
  }
  displayedColumns = ["photo", "matricule", "numero", "nom", "prenom", "classe", "anneeScolaire", "actions"];
  dataSource = new MatTableDataSource([]);
  data = [];
  errorMessage = null;
  yearsSchools = [];
  availableClasses = [];
  paginator;
  openAddYearDialog() {
    const dialogRef = this.dialog.open(AnneescolaireComponent, {
      width: "400px"
    });
    dialogRef.afterClosed().subscribe((result) => {
      if (result) {
        this.loadYearsSchools();
      }
    });
  }
  ngOnInit() {
    this.dataSource.paginator = this.paginator;
    this.paginator.pageSize = 10;
    this.paginator.pageSizeOptions = [10, 20, 30, 40, 50];
    this.paginatorIntl.itemsPerPageLabel = "\xC9l\xE9ments par page";
    this.paginatorIntl.getRangeLabel = (page, pageSize, length) => {
      const of2 = ` sur ${length}`;
      return `${page * pageSize + 1} - ${Math.min((page + 1) * pageSize, length)}${of2}`;
    };
    this.dataSource.filterPredicate = (data, filter2) => {
      return data.matricule.toString().toLowerCase().includes(filter2);
    };
    this.loadYearsSchools();
  }
  loadYearsSchools() {
    this.http.get(`${environment.apiUrl}/years-school`).subscribe({
      next: (response) => {
        this.yearsSchools = response.data;
        this.availableClasses = [];
        this.yearsSchools.forEach((y2) => {
          if (y2.classE) {
            this.availableClasses.push(...y2.classE);
          }
        });
        this.availableClasses = Array.from(new Map(this.availableClasses.map((c2) => [c2.idCls, c2])).values());
        const id = localStorage.getItem("userData");
        if (id) {
          this.loadClasses(id);
        }
      },
      error: (error) => {
        this.errorMessage = "Impossible de charger les ann\xE9es scolaires.";
        console.error("Erreur lors du chargement des ann\xE9es scolaires :", error);
      }
    });
  }
  displayId(id) {
    this.dialog.open(StudentIdDialogComponent, {
      width: "500px",
      panelClass: "custom-dialog-panel",
      data: { id }
    });
  }
  displayIdE(id) {
    this.dialog.open(StudentIdEDialogComponent, {
      width: "500px",
      panelClass: "custom-dialog-panel",
      data: { id }
    });
  }
